local function setSlotItem(config)
    for _, item in pairs(config) do
        ClientHelper.putStringPrefs(string.format("SlotItem-NorImage-%s", item.SlotStyle), item.NorImage)
        ClientHelper.putStringPrefs(string.format("SlotItem-PreImage-%s", item.SlotStyle), item.PreImage)
        ClientHelper.putStringPrefs(string.format("SlotItem-NorStretchOffset-%s", item.SlotStyle), item.NorStretchOffset)
        ClientHelper.putStringPrefs(string.format("SlotItem-PreStretchOffset-%s", item.SlotStyle), item.PreStretchOffset)
    end
end

local function setHotBar(config)
    if config.Background then
        local mainItemBarBg = GUIManager:getWindowByName("Main-ItemBarBg", GUIType.StaticImage)
        local inventoryItemBarBg = GUIManager:getWindowByName("PlayerInventory-ItemBarBg", GUIType.StaticImage)
        for key, value in pairs(config.Background) do
            mainItemBarBg:SetProperty(key, value)
            inventoryItemBarBg:SetProperty(key, value)
        end
    end
    if config.VisibleBar then
        local mainVisibleBar = GUIManager:getWindowByName("Main-VisibleBar", GUIType.StaticImage)
        local inventoryVisibleBar = GUIManager:getWindowByName("PlayerInventory-VisibleBar", GUIType.StaticImage)
        for key, value in pairs(config.VisibleBar) do
            mainVisibleBar:SetProperty(key, value)
            inventoryVisibleBar:SetProperty(key, value)
        end
    end
    if config.ToggleButton then
        local mainToggleButton = GUIManager:getWindowByName("Main-ToggleInventoryButton", GUIType.StaticImage)
        local inventoryToggleButton = GUIManager:getWindowByName("PlayerInventory-ToggleInventoryButton", GUIType.StaticImage)
        for key, value in pairs(config.ToggleButton) do
            mainToggleButton:SetProperty(key, value)
            inventoryToggleButton:SetProperty(key, value)
        end
        if config.ToggleButton.NorImage then
            mainToggleButton:SetProperty("ImageName", config.ToggleButton.NorImage)
        end
        if config.ToggleButton.PreImage then
            inventoryToggleButton:SetProperty("ImageName", config.ToggleButton.PreImage)
        end
    end
    if config.SlotTable then
        local mainSlotTable = GUIManager:getWindowByName("Main-VisibleBar-SlotTable", GUIType.SlotTable)
        local inventorySlotTable = GUIManager:getWindowByName("PlayerInventory-VisibleBar-SlotTable", GUIType.SlotTable)
        for key, value in pairs(config.SlotTable) do
            mainSlotTable:SetProperty(key, value)
            inventorySlotTable:SetProperty(key, value)
        end
    end
    if config.SlotItem and config.SlotTable.SlotStyle then
        for key, value in pairs(config.SlotItem) do
            ClientHelper.putStringPrefs(string.format("SlotItem-%s-%s", key, config.SlotTable.SlotStyle), value)
        end
    end
end

local function setPlayerExp(config)
    local playerExp = GUIManager:getWindowByName("Main-Player-Exp", GUIType.ProgressBar)
    for key, value in pairs(config) do
        playerExp:SetProperty(key, value)
    end
end

local function setArmorPanel(config)
    if config.EquipArmors then
        if config.EquipArmors.SlotItem and config.EquipArmors.SlotStyle then
            local equipArmors = GUIManager:getWindowByName("ArmorPanel-EquipedArmors", GUIType.SlotTable)
            equipArmors:SetProperty("SlotStyle", config.EquipArmors.SlotStyle)
            for key, value in pairs(config.EquipArmors.SlotItem) do
                ClientHelper.putStringPrefs(string.format("SlotItem-%s-%s", key, config.EquipArmors.SlotStyle), value)
            end
        end
    end
    if config.Inventory then
        if config.Inventory.SlotItem and config.Inventory.SlotStyle then
            local inventory = GUIManager:getWindowByName("ArmorPanel-Inventory", GUIType.ScrollableInventory)
            inventory:SetProperty("SlotStyle", config.Inventory.SlotStyle)
            for key, value in pairs(config.Inventory.SlotItem) do
                ClientHelper.putStringPrefs(string.format("SlotItem-%s-%s", key, config.Inventory.SlotStyle), value)
            end
        end
    end
end

local CCustomGUI = {}

function CCustomGUI:init()
    local config = FileUtil.getGameConfigFromYml("CCustomGUI")
    if not config then
        return
    end
    if config.SlotItem then
        setSlotItem(config.SlotItem)
    end
    if config.HotBar then
        setHotBar(config.HotBar)
    end
    if config.PlayerExp then
        setPlayerExp(config.PlayerExp)
    end
    if config.ArmorPanel then
        setArmorPanel(config.ArmorPanel)
    end
end

return CCustomGUI